                vertexList.add(target);
                tour.remove(edge);
                foundNextEdge = true;
                break;
            } else if (target.equals(vertexList.get(vertexList.size() - 1))) {
                vertexList.add(source);
                tour.remove(edge);
                foundNextEdge = true;
                break;
            }
        }

        if (!foundNextEdge) {
            throw new IllegalArgumentException("Il tour non è valido o non è connesso.");
        }
    }

