/**
 * Aggiunge un <code>evento</code> come ultimo evento nel buffer.
 */
public void add(LoggingEvent event) {
    if (size < capacity) {
        buffer[size] = event;
        size++;
    } else {
        // Se il buffer è pieno, sovrascrive il primo elemento (FIFO)
        for (int i = 1; i < capacity; i++) {
            buffer[i - 1] = buffer[i];
        }
        buffer[capacity - 1] = event;
    }
}

