private void pop(final String descriptor) {
    if (descriptor == null || descriptor.isEmpty()) {
        return;
    }
    if (descriptor.startsWith("(")) {
        // È un descrittore di metodo, rimuovi i tipi di argomento
        int endIndex = descriptor.indexOf(')');
